// GET /api/posts?limit=20&after=<cursor>

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = JSON.stringify({
        // Use ISO string so timestamps survive JSON round-tripping precisely.
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64');
}

/**
 * Decode an opaque cursor back into { created_at, id }.
 * Throws on malformed input so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        typeof decoded.created_at !== 'string' ||
        !Number.isInteger(decoded.id)
    ) {
        throw new Error('Malformed cursor');
    }

    // Validate the timestamp is parseable.
    if (Number.isNaN(Date.parse(decoded.created_at))) {
        throw new Error('Malformed cursor');
    }

    return decoded;
}

async function getPosts(req, res) {
    const limit = Math.min(parseInt(req.query.limit) || 20, 100); // clamp to a sane max
    const after = req.query.after;

    // Decode the cursor up front so we can fail fast with a 400.
    let cursor = null;
    if (after !== undefined && after !== '') {
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }
    }

    // Build the query. Fetch limit + 1 rows to detect whether more pages exist.
    let sql;
    let params;

    if (cursor) {
        // Sort is (created_at DESC, id DESC), so "next page" = rows strictly
        // ordered after the cursor. The row-value comparison expresses the
        // compound keyset condition cleanly and uses the same ordering:
        //   (created_at, id) < (cursorCreatedAt, cursorId)
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // LIMIT N+1 trick: an extra row means there's another page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

### Notes on the implementation

- **`(created_at, id) < ($1, $2)` row-value comparison** — PostgreSQL evaluates this as a true lexicographic tuple comparison, which exactly matches the `ORDER BY created_at DESC, id DESC` semantics. It correctly handles ties on `created_at` (the `id` breaks them) without the error-prone `created_at < $1 OR (created_at = $1 AND id < $2)` expansion. Both forms are equivalent and index-friendly.
- **Index recommendation:** create `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` so the keyset lookup is an index range scan rather than a sort.
- **Cursor is opaque:** base64-encoded JSON means clients can't (and shouldn't) parse or construct it — you can change the internal shape later without breaking the API contract.
- I clamped `limit` to a max of 100 to prevent a client from requesting an unbounded page; drop or adjust that if undesired.

### Why cursor-based pagination is superior here

1. **Consistent results under writes.** Offset pagination is positional: if a new post is inserted (or one is deleted) while a user pages through, every subsequent page shifts — rows get skipped or shown twice. A keyset cursor anchors to actual data values, so the result set stays stable even as the table changes. This matters a lot for a `created_at DESC` feed where new rows land at the front.
2. **Constant-time performance at any depth.** `OFFSET n` forces PostgreSQL to scan and discard `n` rows before returning results, so page 10,000 gets progressively slower. The cursor's `WHERE (created_at, id) < (...)` does an index range seek straight to the right spot — page 10,000 costs the same as page 1.
3. **Dropping the COUNT query** removes a full-table scan that grows with the table on every request. `hasMore` (via the N+1 trick) gives the client what it actually needs to drive "load more" without that cost.

The tradeoff: you lose random access to an arbitrary page number and an exact total count — cursors only support sequential forward (and, with a `before` variant, backward) navigation. For an infinite-scroll/feed UI like a posts list, that's exactly the access pattern you want.

