## Cursor-Based Pagination Implementation

```javascript
// ─── Cursor helpers ───────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque, URL-safe base64 cursor string.
 * @param {Date|string} created_at
 * @param {number|string} id
 * @returns {string}
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        created_at: new Date(created_at).toISOString(), // normalize to ISO string
        id: String(id),
    });
    // base64url avoids +/= characters that would need URL-encoding in query params
    return Buffer.from(payload).toString('base64url');
}

/**
 * Decodes a cursor string back into its component parts.
 * Returns null if the cursor is missing, malformed, or has unexpected fields.
 * @param {string} cursor
 * @returns {{ created_at: string, id: string } | null}
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        if (
            typeof parsed !== 'object'          ||
            parsed === null                      ||
            typeof parsed.created_at !== 'string' ||
            isNaN(Date.parse(parsed.created_at)) || // must be a valid timestamp
            parsed.id === undefined
        ) {
            return null;
        }

        return {
            created_at: parsed.created_at,
            id: parsed.id,
        };
    } catch {
        return null;
    }
}

// ─── Endpoint ─────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // Sanitize limit: default 20, hard-cap at 100 to prevent abuse
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterCursor = req.query.after;

    // ── Decode cursor (if provided) ──────────────────────────────────────────
    let cursor = null;

    if (afterCursor !== undefined) {
        cursor = decodeCursor(afterCursor);
        if (cursor === null) {
            return res.status(400).json({
                error: 'Invalid cursor. Re-fetch the first page to get a fresh cursor.',
            });
        }
    }

    // ── Build query ──────────────────────────────────────────────────────────
    //
    // Sort order: created_at DESC, id DESC
    //
    // "After the cursor" in this sort order means rows whose (created_at, id)
    // tuple is strictly less than the cursor's tuple — i.e. they would appear
    // later in the result list.
    //
    // PostgreSQL row-value comparison (a, b) < (x, y) expands to:
    //   a < x  OR  (a = x AND b < y)
    // which is exactly the correct compound predicate for a DESC sort.
    //
    // Fetch limit+1 rows so we can detect whether a next page exists without
    // an expensive COUNT(*). We return only `limit` rows to the caller.

    let result;

    if (cursor) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2::bigint)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1],
        );
    } else {
        // First page — no cursor filter needed
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1],
        );
    }

    // ── Apply LIMIT N+1 trick ────────────────────────────────────────────────
    const rows    = result.rows;
    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows;  // trim the sentinel row

    // Build the next cursor from the LAST row we're actually returning
    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1].created_at, posts[posts.length - 1].id)
        : null;

    // ── Respond ──────────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null when this is the last page
            limit,
        },
    });
}
```

---

## Why cursor-based pagination is superior here

| Concern | Offset (`OFFSET N`) | Cursor (`WHERE (created_at, id) < (…)`) |
|---|---|---|
| **Performance at depth** | DB must count and discard N rows on every request — `O(N)` scan even with an index | Jumps directly to the right position via an index seek — `O(log N)` regardless of depth |
| **Stability under writes** | A new post inserted on page 1 while you read page 2 shifts all offsets, causing **row skips or duplicates** | Cursor anchors to a specific row; inserts/deletes elsewhere don't shift your position |
| **Expensive COUNT** | Needs `SELECT COUNT(*)` to compute `totalPages` — a full table scan that blocks on large tables | Dropped entirely; `hasMore` is free (one extra row fetched) |
| **Infinite / real-time feeds** | Breaks — there is no stable "last page" | Natural fit — clients just keep following `nextCursor` |

The only trade-off is that cursors don't support **random access** (jumping to page 7 directly). For a chronological feed like `/api/posts` that users scroll through sequentially, that's never needed — making this a pure win.

